#include<bits/stdc++.h>
using namespace std;
int dx[]={0,-1,0,1,1,-1,1,-1};
int dy[]={1,0,-1,0,1,1,-1,-1};
bool v[1001][1001]={0};
long long a[1001][1001],n,m,ans1;
int dfs(int x,int y){
    int flag1=1;
    v[x][y]=1;
    for(int i=0;i<=7;i++){
        int mx=x+dx[i];
        int my=y+dy[i];
        if(mx<=0||my<=0||mx>n||my>m) continue;

        if(a[mx][my]>a[x][y]){
           flag1=0; 
        }else if(a[mx][my]==a[x][y]){
            if(v[mx][my]) continue;
            int ans=dfs(mx,my);
            if(ans==0){
                flag1=0;
            }
        }
    }
    return flag1;
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            cin>>a[i][j];
        }
    }
    for(int i=1;i<=n;i++){
        for(int j=1;j<=m;j++){
            if(!v[i][j]){
                int ans=dfs(i,j);
                if(ans==1){
                    ans1++;
                }
            }
        }
    }
    cout<<ans1;
    return 0;
}
